class Solution {
    public long maxGCDScore(int[] nums, int k) {
        long maxScore = 0;
        for (int i = 0; i < nums.length; i++) {
            for (int j = i; j < nums.length; j++) {
                int[] subarray = Arrays.copyOfRange(nums, i, j + 1);
                long score = getScore(subarray, k);
                maxScore = Math.max(maxScore, score);
            }
        }
        return maxScore;
    }

    private long getScore(int[] subarray, int k) {
        long maxScore = 0;
        for (int mask = 0; mask < (1 << subarray.length); mask++) {
            if (Integer.bitCount(mask) <= k) {
                int[] modifiedSubarray = modifySubarray(subarray, mask);
                long score = (long) modifiedSubarray.length * gcd(modifiedSubarray);
                maxScore = Math.max(maxScore, score);
            }
        }
        return maxScore;
    }

    private int[] modifySubarray(int[] subarray, int mask) {
        int[] modifiedSubarray = new int[subarray.length];
        for (int i = 0; i < subarray.length; i++) {
            modifiedSubarray[i] = (mask & (1 << i)) != 0 ? subarray[i] * 2 : subarray[i];
        }
        return modifiedSubarray;
    }

    private long gcd(int[] nums) {
        long gcd = nums[0];
        for (int i = 1; i < nums.length; i++) {
            gcd = gcd(gcd, nums[i]);
        }
        return gcd;
    }

    private long gcd(long a, long b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
